import{_ as t,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse(`{"title":"Historique des versions: Évolution des fonctionnalités | opencode-agent-skills","description":"Découvrez l'évolution des versions du plugin OpenCode Agent Skills. Ce tutoriel couvre toutes les mises à jour majeures, corrections de bugs, améliorations architecturales et changements majeurs de la v0.1.0 à la v0.6.4.","frontmatter":{"title":"Historique des versions: Évolution des fonctionnalités | opencode-agent-skills","sidebarTitle":"Quoi de neuf","subtitle":"Historique des versions","description":"Découvrez l'évolution des versions du plugin OpenCode Agent Skills. Ce tutoriel couvre toutes les mises à jour majeures, corrections de bugs, améliorations architecturales et changements majeurs de la v0.1.0 à la v0.6.4.","tags":["Mises à jour","changelog","Historique des versions"],"order":3},"headers":[],"relativePath":"fr/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"fr/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}`),s={name:"fr/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function n(d,e,a,l,c,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="historique-des-versions" tabindex="-1">Historique des versions <a class="header-anchor" href="#historique-des-versions" aria-label="Permalink to &quot;Historique des versions&quot;">​</a></h1><p>Ce document enregistre toutes les mises à jour du plugin OpenCode Agent Skills. Grâce à l&#39;historique des versions, vous pouvez suivre le parcours d&#39;évolution des fonctionnalités, les problèmes résolus et les améliorations architecturales.</p><div class="tip custom-block"><p class="custom-block-title">Version actuelle</p><p>La dernière version stable est la <strong>v0.6.4</strong> (20 janvier 2026)</p></div><h2 id="chronologie-des-versions" tabindex="-1">Chronologie des versions <a class="header-anchor" href="#chronologie-des-versions" aria-label="Permalink to &quot;Chronologie des versions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date de publication</th><th>Type</th><th>Contenu principal</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>Correction</td><td>Analyse YAML, support Claude v2</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>Amélioration</td><td>Optimisation des suggestions de compétences</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>Correction</td><td>Séparation du nom de compétence et du nom de répertoire</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>Amélioration</td><td>Éviter de recommander les compétences déjà chargées</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>Nouvelle fonctionnalité</td><td>Correspondance sémantique, précalcul des embeddings</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>Amélioration</td><td>Suggestions de correspondance floue, refactoring</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>Amélioration</td><td>Simplification de l&#39;installation</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>Amélioration</td><td>Recherche récursive des scripts</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>Correction</td><td>Gestion des liens symboliques</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>Correction</td><td>Préservation du mode agent</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>Correction</td><td>Problème de changement de modèle</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>Nouvelle fonctionnalité</td><td>Fonction de liste de fichiers</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>Nouvelle fonctionnalité</td><td>Mode Superpowers</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>Initial</td><td>4 outils, découverte multi-localisation</td></tr></tbody></table><h2 id="journal-des-modifications-detaille" tabindex="-1">Journal des modifications détaillé <a class="header-anchor" href="#journal-des-modifications-detaille" aria-label="Permalink to &quot;Journal des modifications détaillé&quot;">​</a></h2><h3 id="v0-6-4-20-janvier-2026" tabindex="-1">v0.6.4 (20 janvier 2026) <a class="header-anchor" href="#v0-6-4-20-janvier-2026" aria-label="Permalink to &quot;v0.6.4 (20 janvier 2026)&quot;">​</a></h3><p><strong>Corrections :</strong></p><ul><li>Correction de l&#39;analyse du frontmatter YAML pour les descriptions multilignes de compétences (prise en charge des syntaxes de scalaires de bloc <code>|</code> et <code>&gt;</code>), en remplaçant l&#39;analyseur personnalisé par la bibliothèque <code>yaml</code></li><li>Ajout de la prise en charge du format Claude plugin v2, <code>installed_plugins.json</code> utilise désormais un tableau d&#39;installations de plugins plutôt qu&#39;un objet unique</li></ul><p><strong>Améliorations :</strong></p><ul><li>La découverte du cache des plugins Claude Code prend désormais en charge la nouvelle structure de répertoires imbriqués (<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>)</li></ul><h3 id="v0-6-3-16-decembre-2025" tabindex="-1">v0.6.3 (16 décembre 2025) <a class="header-anchor" href="#v0-6-3-16-decembre-2025" aria-label="Permalink to &quot;v0.6.3 (16 décembre 2025)&quot;">​</a></h3><p><strong>Améliorations :</strong></p><ul><li>Optimisation de l&#39;invite d&#39;évaluation des compétences pour empêcher le modèle d&#39;envoyer des messages de type &quot;aucune compétence nécessaire&quot; à l&#39;utilisateur (l&#39;utilisateur ne voit pas l&#39;invite d&#39;évaluation cachée)</li></ul><h3 id="v0-6-2-15-decembre-2025" tabindex="-1">v0.6.2 (15 décembre 2025) <a class="header-anchor" href="#v0-6-2-15-decembre-2025" aria-label="Permalink to &quot;v0.6.2 (15 décembre 2025)&quot;">​</a></h3><p><strong>Corrections :</strong></p><ul><li>La validation des compétences permet désormais que le nom du répertoire diffère du <code>name</code> dans le frontmatter SKILL.md. Le <code>name</code> dans le frontmatter est l&#39;identifiant standard, le nom du répertoire sert uniquement à l&#39;organisation. Cela est conforme à la spécification Anthropic Agent Skills.</li></ul><h3 id="v0-6-1-13-decembre-2025" tabindex="-1">v0.6.1 (13 décembre 2025) <a class="header-anchor" href="#v0-6-1-13-decembre-2025" aria-label="Permalink to &quot;v0.6.1 (13 décembre 2025)&quot;">​</a></h3><p><strong>Améliorations :</strong></p><ul><li>La recommandation dynamique de compétences suit désormais les compétences déjà chargées par session, évitant de recommander à nouveau les compétences déjà chargées et réduisant les invites redondantes et l&#39;utilisation du contexte</li></ul><h3 id="v0-6-0-12-decembre-2025" tabindex="-1">v0.6.0 (12 décembre 2025) <a class="header-anchor" href="#v0-6-0-12-decembre-2025" aria-label="Permalink to &quot;v0.6.0 (12 décembre 2025)&quot;">​</a></h3><p><strong>Nouveautés :</strong></p><ul><li><strong>Correspondance sémantique des compétences</strong> : après l&#39;injection initiale de la liste des compétences, les messages suivants utilisent les embeddings locaux pour correspondre avec les descriptions des compétences</li><li>Nouvelle dépendance <code>@huggingface/transformers</code> pour la génération d&#39;embeddings locaux (version quantifiée all-MiniLM-L6-v2)</li><li>Injection d&#39;une invite d&#39;évaluation en 3 étapes (EVALUATE → DECIDE → ACTIVATE) lorsqu&#39;un message correspond à une compétence disponible, encourageant le chargement de la compétence (inspiré par <a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">l&#39;article de blog</a> de <a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a>)</li><li>Mise en cache sur disque des embeddings pour une correspondance à faible latence (~/.cache/opencode-agent-skills/)</li><li>Nettoyage des sessions sur l&#39;événement <code>session.deleted</code></li></ul><h3 id="v0-5-0-11-decembre-2025" tabindex="-1">v0.5.0 (11 décembre 2025) <a class="header-anchor" href="#v0-5-0-11-decembre-2025" aria-label="Permalink to &quot;v0.5.0 (11 décembre 2025)&quot;">​</a></h3><p><strong>Nouveautés :</strong></p><ul><li>Ajout de suggestions de correspondance floue &quot;Vouliez-vous dire...&quot; dans tous les outils (<code>use_skill</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>get_available_skills</code>)</li></ul><p><strong>Améliorations :</strong></p><ul><li><strong>Changement majeur</strong> : renommage de l&#39;outil <code>find_skills</code> en <code>get_available_skills</code> pour une intention plus claire</li><li><strong>Interne</strong> : réorganisation de la base de code en modules indépendants (<code>claude.ts</code>, <code>skills.ts</code>, <code>tools.ts</code>, <code>utils.ts</code>, <code>superpowers.ts</code>) pour améliorer la maintenabilité</li><li><strong>Interne</strong> : amélioration de la qualité du code en supprimant les commentaires générés par IA et le code inutile</li></ul><h3 id="v0-4-1-8-decembre-2025" tabindex="-1">v0.4.1 (8 décembre 2025) <a class="header-anchor" href="#v0-4-1-8-decembre-2025" aria-label="Permalink to &quot;v0.4.1 (8 décembre 2025)&quot;">​</a></h3><p><strong>Améliorations :</strong></p><ul><li>L&#39;installation utilise désormais le package npm via la configuration OpenCode, plutôt que git clone + lien symbolique</li></ul><p><strong>Suppressions :</strong></p><ul><li>Suppression de <code>INSTALL.md</code> (plus nécessaire après simplification de l&#39;installation)</li></ul><h3 id="v0-4-0-5-decembre-2025" tabindex="-1">v0.4.0 (5 décembre 2025) <a class="header-anchor" href="#v0-4-0-5-decembre-2025" aria-label="Permalink to &quot;v0.4.0 (5 décembre 2025)&quot;">​</a></h3><p><strong>Améliorations :</strong></p><ul><li>La découverte de scripts recherche désormais récursivement tout le répertoire de compétences (profondeur maximale 10), plutôt que seulement le répertoire racine et le sous-répertoire <code>scripts/</code></li><li>Les scripts sont désormais identifiés par chemin relatif (par exemple <code>tools/build.sh</code>) plutôt que par nom de base</li><li>Renommage du paramètre <code>skill_name</code> en <code>skill</code> dans les outils <code>read_skill_file</code>, <code>run_skill_script</code> et <code>use_skill</code></li><li>Renommage du paramètre <code>script_name</code> en <code>script</code> dans l&#39;outil <code>run_skill_script</code></li></ul><h3 id="v0-3-3-2-decembre-2025" tabindex="-1">v0.3.3 (2 décembre 2025) <a class="header-anchor" href="#v0-3-3-2-decembre-2025" aria-label="Permalink to &quot;v0.3.3 (2 décembre 2025)&quot;">​</a></h3><p><strong>Corrections :</strong></p><ul><li>Correction de la détection des fichiers et répertoires pour gérer correctement les liens symboliques en utilisant <code>fs.stat</code></li></ul><h3 id="v0-3-2-30-novembre-2025" tabindex="-1">v0.3.2 (30 novembre 2025) <a class="header-anchor" href="#v0-3-2-30-novembre-2025" aria-label="Permalink to &quot;v0.3.2 (30 novembre 2025)&quot;">​</a></h3><p><strong>Corrections :</strong></p><ul><li>Préservation du mode agent lors de l&#39;injection de messages synthétiques au début de la session</li></ul><h3 id="v0-3-1-28-novembre-2025" tabindex="-1">v0.3.1 (28 novembre 2025) <a class="header-anchor" href="#v0-3-1-28-novembre-2025" aria-label="Permalink to &quot;v0.3.1 (28 novembre 2025)&quot;">​</a></h3><p><strong>Corrections :</strong></p><ul><li>Correction du changement de modèle inattendu lors de l&#39;utilisation des outils de compétence en passant explicitement le modèle actuel dans l&#39;opération <code>noReply</code> (solution temporaire pour le problème opencode #4475)</li></ul><h3 id="v0-3-0-27-novembre-2025" tabindex="-1">v0.3.0 (27 novembre 2025) <a class="header-anchor" href="#v0-3-0-27-novembre-2025" aria-label="Permalink to &quot;v0.3.0 (27 novembre 2025)&quot;">​</a></h3><p><strong>Nouveautés :</strong></p><ul><li>Ajout d&#39;une liste de fichiers dans la sortie <code>use_skill</code></li></ul><h3 id="v0-2-0-26-novembre-2025" tabindex="-1">v0.2.0 (26 novembre 2025) <a class="header-anchor" href="#v0-2-0-26-novembre-2025" aria-label="Permalink to &quot;v0.2.0 (26 novembre 2025)&quot;">​</a></h3><p><strong>Nouveautés :</strong></p><ul><li>Ajout de la prise en charge du mode Superpowers</li><li>Ajout d&#39;une preuve de publication</li></ul><h3 id="v0-1-0-26-novembre-2025" tabindex="-1">v0.1.0 (26 novembre 2025) <a class="header-anchor" href="#v0-1-0-26-novembre-2025" aria-label="Permalink to &quot;v0.1.0 (26 novembre 2025)&quot;">​</a></h3><p><strong>Nouveautés :</strong></p><ul><li>Ajout de l&#39;outil <code>use_skill</code> pour charger le contenu des compétences dans le contexte</li><li>Ajout de l&#39;outil <code>read_skill_file</code> pour lire les fichiers de support dans le répertoire de compétences</li><li>Ajout de l&#39;outil <code>run_skill_script</code> pour exécuter des scripts depuis le répertoire de compétences</li><li>Ajout de l&#39;outil <code>find_skills</code> pour rechercher et lister les compétences disponibles</li><li>Ajout de la découverte de compétences multi-localisation (niveau projet, niveau utilisateur et emplacements compatibles Claude)</li><li>Ajout de la validation du frontmatter conforme à la spécification Anthropic Agent Skills v1.0</li><li>Ajout de l&#39;injection automatique de la liste des compétences au début de la session et après la compression du contexte</li></ul><p><strong>Nouveaux contributeurs :</strong></p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (mainteneur)</li></ul><h2 id="vue-d-ensemble-de-l-evolution-des-fonctionnalites" tabindex="-1">Vue d&#39;ensemble de l&#39;évolution des fonctionnalités <a class="header-anchor" href="#vue-d-ensemble-de-l-evolution-des-fonctionnalites" aria-label="Permalink to &quot;Vue d&#39;ensemble de l&#39;évolution des fonctionnalités&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Version d&#39;introduction</th><th>Parcours d&#39;évolution</th></tr></thead><tbody><tr><td>4 outils de base</td><td>v0.1.0</td><td>v0.5.0 ajout de la correspondance floue</td></tr><tr><td>Découverte de compétences multi-localisation</td><td>v0.1.0</td><td>v0.4.1 simplification de l&#39;installation, v0.6.4 support Claude v2</td></tr><tr><td>Injection automatique du contexte</td><td>v0.1.0</td><td>v0.3.0 ajout de la liste de fichiers, v0.6.1 éviter les recommandations répétées</td></tr><tr><td>Mode Superpowers</td><td>v0.2.0</td><td>Stable en continu</td></tr><tr><td>Recherche récursive des scripts</td><td>v0.4.0</td><td>v0.3.3 correction des liens symboliques</td></tr><tr><td>Recommandation par correspondance sémantique</td><td>v0.6.0</td><td>v0.6.1 éviter les répétitions, v0.6.3 optimisation des invites</td></tr><tr><td>Suggestions de correspondance floue</td><td>v0.5.0</td><td>Stable en continu</td></tr></tbody></table><h2 id="notes-sur-les-changements-majeurs" tabindex="-1">Notes sur les changements majeurs <a class="header-anchor" href="#notes-sur-les-changements-majeurs" aria-label="Permalink to &quot;Notes sur les changements majeurs&quot;">​</a></h2><h3 id="v0-6-0-fonctionnalite-de-correspondance-semantique" tabindex="-1">v0.6.0 : Fonctionnalité de correspondance sémantique <a class="header-anchor" href="#v0-6-0-fonctionnalite-de-correspondance-semantique" aria-label="Permalink to &quot;v0.6.0 : Fonctionnalité de correspondance sémantique&quot;">​</a></h3><p>Introduction de la capacité de correspondance sémantique basée sur des embeddings locaux, permettant à l&#39;IA de recommander automatiquement des compétences pertinentes en fonction du contenu du message de l&#39;utilisateur, sans nécessiter de mémoriser manuellement les noms des compétences.</p><ul><li><strong>Détails techniques</strong> : utilisation du modèle <code>all-MiniLM-L6-v2</code> de HuggingFace (quantification q8)</li><li><strong>Mécanisme de cache</strong> : les résultats des embeddings sont mis en cache dans <code>~/.cache/opencode-agent-skills/</code>, améliorant la vitesse des correspondances ultérieures</li><li><strong>Processus de correspondance</strong> : message utilisateur → embedding → calcul de similarité cosinus avec les descriptions de compétences → Top 5 recommandations (seuil 0,35)</li></ul><h3 id="v0-5-0-refactoring-et-renommage-des-outils" tabindex="-1">v0.5.0 : Refactoring et renommage des outils <a class="header-anchor" href="#v0-5-0-refactoring-et-renommage-des-outils" aria-label="Permalink to &quot;v0.5.0 : Refactoring et renommage des outils&quot;">​</a></h3><p>Refactoring de l&#39;architecture du code vers une conception modulaire, avec des noms d&#39;outils plus clairs :</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-amelioration-du-mecanisme-de-decouverte-des-scripts" tabindex="-1">v0.4.0 : Amélioration du mécanisme de découverte des scripts <a class="header-anchor" href="#v0-4-0-amelioration-du-mecanisme-de-decouverte-des-scripts" aria-label="Permalink to &quot;v0.4.0 : Amélioration du mécanisme de découverte des scripts&quot;">​</a></h3><p>La découverte de scripts passe de &quot;répertoire racine uniquement + scripts/&quot; à &quot;recherche récursive de tout le répertoire de compétences&quot; (profondeur maximale 10), prenant en charge une organisation plus flexible des scripts.</p><h3 id="v0-2-0-integration-superpowers" tabindex="-1">v0.2.0 : Intégration Superpowers <a class="header-anchor" href="#v0-2-0-integration-superpowers" aria-label="Permalink to &quot;v0.2.0 : Intégration Superpowers&quot;">​</a></h3><p>Ajout de la prise en charge du mode de flux de travail Superpowers, nécessitant l&#39;installation de la compétence <code>using-superpowers</code> et la définition de la variable d&#39;environnement <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>.</p><hr><h2 id="annexe-references-du-code-source" tabindex="-1">Annexe : Références du code source <a class="header-anchor" href="#annexe-references-du-code-source" aria-label="Permalink to &quot;Annexe : Références du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer et voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 24 janvier 2026</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Numéros de ligne</th></tr></thead><tbody><tr><td>Numéro de version actuel</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>Historique des versions</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>Informations clés sur les versions :</strong></p><ul><li><code>v0.6.4</code> : Version actuelle (20 janvier 2026)</li><li><code>v0.6.0</code> : Introduction de la correspondance sémantique (12 décembre 2025)</li><li><code>v0.5.0</code> : Version de refactoring (11 décembre 2025)</li><li><code>v0.1.0</code> : Version initiale (26 novembre 2025)</li></ul></details>',72)])])}const h=t(s,[["render",n]]);export{p as __pageData,h as default};
